+
+    await handler({
+      event: {
+        type: "message",
+        user: "U1",
+        text: "/elevated off",
+        ts: "123",
+        channel: "C1",
+        channel_type: "channel",
+      },
+    });
+
+    await flush();
+    controller.abort();
+    await run;
+
